customCSS:
/* Chrome Warfare - Industrial HUD */
@import url('https://fonts.googleapis.com/css2?family=Quantico:wght@400;700&family=Chakra+Petch:wght@300;400;500;600;700&family=Source+Code+Pro:wght@400;500&display=swap');

/* Industrial grid overlay */
.cyber-grid {
  background:
    linear-gradient(rgba(204, 34, 51, 0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(204, 34, 51, 0.02) 1px, transparent 1px);
  background-size: 50px 50px;
  animation: none;
}

.cyber-glow {
  background:
    radial-gradient(ellipse 500px 350px at 50% 5%, rgba(204, 34, 51, 0.06), transparent),
    radial-gradient(ellipse 400px 300px at 80% 80%, rgba(204, 68, 0, 0.03), transparent);
}

/* Red scanner line */
.scan-line {
  background: linear-gradient(
    to bottom,
    transparent 0%,
    rgba(204, 34, 51, 0.05) 50%,
    transparent 100%
  );
  animation: scanLines 5s linear infinite;
}

/* Chrome-bordered cards with red accent */
.stat-card {
  border: 1px solid rgba(192, 192, 200, 0.12);
  border-left: 3px solid #cc2233;
  border-radius: 2px;
  position: relative;
}

.stat-card::before {
  background: linear-gradient(90deg, #cc2233, #cc4400, #ddaa22);
  height: 2px;
}

/* Chrome corner brackets */
.stat-card::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 14px;
  height: 14px;
  border-bottom: 2px solid rgba(192, 192, 200, 0.25);
  border-left: 2px solid rgba(192, 192, 200, 0.25);
  pointer-events: none;
}

.miner-card,
.health-card,
.lifetime-card {
  border: 1px solid rgba(192, 192, 200, 0.1);
  border-radius: 2px;
}

.miner-card {
  border-left: 3px solid rgba(204, 34, 51, 0.5);
}

/* Red targeting glow on hover */
.stat-card:hover {
  border-color: rgba(204, 34, 51, 0.4);
  box-shadow:
    0 0 15px rgba(204, 34, 51, 0.15),
    0 0 30px rgba(204, 34, 51, 0.05);
}

.miner-card:hover {
  border-color: rgba(192, 192, 200, 0.25);
  box-shadow:
    0 0 12px rgba(204, 34, 51, 0.1),
    0 1px 0 rgba(192, 192, 200, 0.08);
}

/* Stat values — red HUD glow */
.stat-value {
  text-shadow: 0 0 10px rgba(204, 34, 51, 0.5), 0 0 20px rgba(204, 34, 51, 0.15);
  letter-spacing: 1px;
}

/* Offline miners — critical red */
.miner-status-dot.offline {
  box-shadow: 0 0 8px rgba(204, 34, 51, 0.7), 0 0 16px rgba(204, 34, 51, 0.3);
}

.miner-card.offline {
  border-left-color: #cc2233;
}

/* Section headers — red underline */
.section-header h2 {
  border-bottom: 2px solid rgba(204, 34, 51, 0.25);
  padding-bottom: 0.5rem;
  letter-spacing: 3px;
  text-transform: uppercase;
}

/* Celebration — molten amber burst */
.celebration-title {
  color: #ddaa22 !important;
  text-shadow: 0 0 25px rgba(221, 170, 34, 0.5), 0 0 50px rgba(204, 68, 0, 0.3) !important;
}

.celebration-icon {
  filter: hue-rotate(-10deg) brightness(1.2) saturate(1.3);
}

/* Industrial logo */
.logo {
  text-shadow: 0 0 15px rgba(204, 34, 51, 0.4);
  letter-spacing: 5px;
  text-transform: uppercase;
}

/* Alert badges — amber */
.badge {
  border-color: rgba(204, 68, 0, 0.35);
  letter-spacing: 1px;
}

/* Scrollbar — chrome with red accent */
::-webkit-scrollbar-thumb {
  background: rgba(204, 34, 51, 0.3);
  border-radius: 2px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(204, 34, 51, 0.5);
}
